import{_ as r,o as a,c as e,a2 as p}from"./chunks/framework.BWuWLRhz.js";const o="/images/11-awkward-things-about-email/unequal.png",s="/images/11-awkward-things-about-email/reply-to-all-1.png",n="/images/11-awkward-things-about-email/reply-to-all-2.png",g="/images/11-awkward-things-about-email/reply-to-all-3.png",l="/images/11-awkward-things-about-email/reply-to-all-4.png",i="/images/11-awkward-things-about-email/reply-to-all-5.png",A="/images/11-awkward-things-about-email/reply-to-all-6.png",m="/images/11-awkward-things-about-email/all-caps.png",h="/images/11-awkward-things-about-email/OLD.png",b="/images/11-awkward-things-about-email/late-responder-1.png",c="/images/11-awkward-things-about-email/late-responder-2.png",_="/images/11-awkward-things-about-email/late-responder-3.png",w="/images/11-awkward-things-about-email/late-responder-4.png",f="/images/11-awkward-things-about-email/Greeting.png",k="/images/11-awkward-things-about-email/greeting2.png",d="/images/11-awkward-things-about-email/xoxo.png",u="/images/11-awkward-things-about-email/robot-phrases.png",y="/images/11-awkward-things-about-email/periods.png",U="/images/11-awkward-things-about-email/exclamations.png",G="/images/11-awkward-things-about-email/exclamation-period.png",I="/images/11-awkward-things-about-email/exclamation-question.png",T="/images/11-awkward-things-about-email/exclamation-graph.png",H="/images/11-awkward-things-about-email/ellipses.png",x="/images/11-awkward-things-about-email/epic-correspondence.png",q="/images/11-awkward-things-about-email/haha.png",Y="/images/11-awkward-things-about-email/hurtful.png",P="/images/11-awkward-things-about-email/disaster.png",S="/images/11-awkward-things-about-email/disaster-2.png",Z="/images/11-awkward-things-about-email/pinit_fg_en_rect_gray_20.png",C=JSON.parse('{"title":"11 Awkward Things About Email","description":"","frontmatter":{"title":"11 Awkward Things About Email","titleZh":"电子邮件的 11 个尴尬之处","date":"2013-12-04T00:00:00.000Z","originalUrl":"https://waitbutwhy.com/2013/12/11-awkward-things-about-email.html","slug":"11-awkward-things-about-email"},"headers":[],"relativePath":"posts/11-awkward-things-about-email.md","filePath":"posts/11-awkward-things-about-email.md","lastUpdated":1782886257000}'),j={name:"posts/11-awkward-things-about-email.md"};function E(J,t,O,Q,W,N){return a(),e("div",null,[...t[0]||(t[0]=[p('<h1 id="电子邮件的-11-个尴尬之处-·-11-awkward-things-about-email" tabindex="-1">电子邮件的 11 个尴尬之处 · 11 Awkward Things About Email <a class="header-anchor" href="#电子邮件的-11-个尴尬之处-·-11-awkward-things-about-email" aria-label="Permalink to &quot;电子邮件的 11 个尴尬之处 · 11 Awkward Things About Email&quot;">​</a></h1><blockquote><p>原文:<a href="https://waitbutwhy.com/2013/12/11-awkward-things-about-email.html" target="_blank" rel="noreferrer">https://waitbutwhy.com/2013/12/11-awkward-things-about-email.html</a> · 2013-12-04</p></blockquote><p>电子邮件就是那种已经彻底融入你人生的东西,没得商量。我们大多数人都认识那种关了 Facebook 账号、或者干脆从没注册过的人——一副小小的、跺着脚为自尊做抗争的样子;你甚至可能认识那种因为自己不用智能手机而沾沾自喜的人。</p><p>但在成年互联网用户的世界里,没人可以不用邮箱。</p><p>今天不用邮箱,基本等同于没有电话号码——你得<em>真的</em>活得特立独行才能走到那一步。</p><p>于是我们都在这儿,往写信框里敲字,跟收件箱搏斗,总体进行得还算顺利——但和任何社交互动的世界一样,邮件也有它的难处。</p><p>来聊聊邮件生活里 11 件特别尴尬的事——</p><p><strong>1)权力关系不对等的邮件往来。</strong></p><p><a href="https://2.bp.blogspot.com/-D8dfZJD-p6k/Up74Zqw429I/AAAAAAAAGgg/pyeaf_rWqlc/s1600/unequal.png" target="_blank" rel="noreferrer"><img src="'+o+'" alt=""></a></p><p>如果和你邮件往来的那个人:</p><ul><li>打错字而你没有</li><li>不用标点而你用</li><li>不用大写而你用</li><li>回信慢腾腾而你秒回</li><li>用超短的回复来应付你长篇大论、精心撰写的邮件</li></ul><p>那你就是他的小弟。</p><p>邮件里的不平等权力关系可能由很多原因造成——职级差距、年龄差距、&quot;顾客永远是对的&quot;这种情况、一堆人都在给同一个人写邮件——但通常都是,写高质量邮件的那个人想从/需要从写低质量邮件的那个人那儿得到什么。就这么简单。</p><p><strong>2)和不懂科技的婴儿潮一代通邮件。</strong></p><p>不是所有婴儿潮一代——你知道我说的是哪种人。</p><p>他们是最后一批还在用 AOL 邮箱的人。他们会把一篇文章的纸质版扫描下来当附件发给你,而不是发一个文章链接。他们写 e-mail 这个词的时候中间还带个连字符。而且他们不知道世界上还有&quot;回复全部&quot;这种功能:</p><p><a href="https://2.bp.blogspot.com/-SPaf-ewIVmw/Up74Xfs4mbI/AAAAAAAAGfo/fjY6kY35ki0/s1600/reply+to+all+1.png" target="_blank" rel="noreferrer"><img src="'+s+'" alt=""></a><br><a href="https://4.bp.blogspot.com/-_tvAExAwDbg/Up74XsAhS9I/AAAAAAAAGfw/EE6zEXQHejU/s1600/reply+to+all+2.png" target="_blank" rel="noreferrer"><img src="'+n+'" alt=""></a><br><a href="https://1.bp.blogspot.com/-n8OZRZXtuPE/UqU-ZPMJfGI/AAAAAAAAGik/c0PuWlMyjUs/s1600/reply+to+all+3.png" target="_blank" rel="noreferrer"><img src="'+g+'" alt=""></a><br><a href="https://4.bp.blogspot.com/-582P6tULmLI/Up74a7fAtII/AAAAAAAAGgs/jtq_rvMocKU/s1600/reply+to+all+4.png" target="_blank" rel="noreferrer"><img src="'+l+'" alt=""></a><br><a href="https://3.bp.blogspot.com/-UJkX8F2Cj6w/Up74YtfxZxI/AAAAAAAAGgA/yLK8yIOApKg/s1600/reply+to+all+5.png" target="_blank" rel="noreferrer"><img src="'+i+'" alt=""></a></p><p><a href="https://1.bp.blogspot.com/-WDQr0oQraa8/UqU-ZOxJ1VI/AAAAAAAAGio/03Zn8kPBawI/s1600/reply+to+all+6.png" target="_blank" rel="noreferrer"><img src="'+A+'" alt=""></a></p><p>有时候,你会碰到那种特别不懂科技的婴儿潮一代长辈,他们莫名其妙地全用大写字母写邮件。</p><p><a href="https://1.bp.blogspot.com/-9WtU_EzAXQU/Up74UpQJVPI/AAAAAAAAGeo/TH5jOUxCU38/s1600/all+caps.png" target="_blank" rel="noreferrer"><img src="'+m+'" alt=""></a></p><p><strong>3) 和 1930 年之前出生的人发邮件。</strong></p><p><a href="https://3.bp.blogspot.com/-tA1XSZNHlTE/Up74SITV3FI/AAAAAAAAGdg/DDXTO4IndQg/s1600/OLD.png" target="_blank" rel="noreferrer"><img src="'+h+'" alt=""></a></p><p>对我奶奶来说——她会在浏览器窗口不小心被最小化时告诉我她的「机器坏了」——像「转发」、「附件」、「链接」这样的词并没有简单、具体的定义,它们只是些她听说过但不理解的、模糊而复杂的概念。</p><p>她对电子邮件的感受,就跟我对下面这句话的感受一样:</p><p><em>发展中国家的央行正在收紧政策并干预货币市场,以应对本币贬值可能对通胀产生影响的担忧,尽管非金融企业债券和商业票据的总发行量已经放缓,利率波动性也大幅下降,这可能表明追逐收益率的行为可能又在增加。</em></p><p>如果你不是懒到连一封信都不愿意写,那么和 1920 年代出生的人保持手写信件往来会是个不错的主意,尤其还有个附加好处——50 年后,一封来自 1920 年代出生的人的信将会是件很酷的收藏品。</p><p><strong>4) 群发邮件链里的迟到回复者。</strong></p><p><a href="https://3.bp.blogspot.com/-21wzJyWayzs/Up74Vsn0LzI/AAAAAAAAGe8/Z6nZOjJ-v3g/s1600/late+responder+1.png" target="_blank" rel="noreferrer"><img src="'+b+'" alt=""></a><br><a href="https://2.bp.blogspot.com/-QZqbnHzNZ1c/Up74Y9L0zkI/AAAAAAAAGgI/ZqYHBuc4uKk/s1600/late+responder+2.png" target="_blank" rel="noreferrer"><img src="'+c+'" alt=""></a><br><a href="https://3.bp.blogspot.com/-mSCujYOSaH0/Up74WbwF2BI/AAAAAAAAGfY/7WXYNS1fLtk/s1600/late+responder+3.png" target="_blank" rel="noreferrer"><img src="'+_+'" alt=""></a><br><a href="https://2.bp.blogspot.com/-9G-ruN8rCdE/Up74WdiLwsI/AAAAAAAAGfU/z-hwFMWL8os/s1600/late+responder+4.png" target="_blank" rel="noreferrer"><img src="'+w+'" alt=""></a></p><p><strong>5) 纠结邮件开头怎么称呼一个不太熟的朋友。</strong></p><p>为了方便起见,我们在某个时候已经共同约定好了一套规则,用来称呼各种类别的邮件对象。</p><p><a href="https://3.bp.blogspot.com/-mtiH8ksrfc4/Up8SNl5HvII/AAAAAAAAGhY/3CMLgjaGuEY/s1600/Greeting.png" target="_blank" rel="noreferrer"><img src="'+f+'" alt=""></a></p><p>看出问题了吗?</p><p>“Hi ____”这种问候方式,对所有不太熟的人来说都是一种保持距离、中立、专业的友好。当你和某人的关系向前迈进一步,就升级到了更热情、更随意的 Hey 区。而对于真正亲近的人,你干脆可以省略问候语——没人会用「Hey Mom」开头写邮件。</p><p>但绿色区域那一类人怎么办呢?——他们比一般熟人要亲近一些,用「Hey」问候显得太正式太疏远,但你们联系又没频繁到可以突然发邮件、连招呼都不打就开始说话。你到底该怎么给那个每两年才联系一次的大学朋友,或者那个曾经变成朋友后来又基本失联的老同事写邮件开头?</p><p>不容易。而且和所有其他问候语不同,这个需要点创造力。一些可能性:</p><p><strong>– Hey John!</strong> —— 感叹号在说:「这不是普通的 Hey 问候——我在笑,而且格外兴奋,因为我们关系不错,你在我生命里是件好事。」</p><p><strong>– Johnny!</strong> —— 对「Hey John!」邮件的典型回复问候。它承认你们已经到了叫昵称的份上,同时也用感叹号一起庆祝你们的友谊。</p><p><strong>– Hey man</strong> —— 这是男性熟人或小朋友之间应对绿色区域的招数。相当于问候版的友好拍背。</p><p><strong>– Sammmm</strong> —— 女生处理绿色区域的工具。</p><p><strong>– Heyyy</strong> —— 多出来的 Y 在说:「就是顺便过来说点事,咱们是朋友嘛,所以有时候就是会顺便过来。」</p><p><a href="https://3.bp.blogspot.com/-zzND1j77j2o/Up74UwzcAMI/AAAAAAAAGek/9mG2d5bGs6I/s1600/greeting2.png" target="_blank" rel="noreferrer"><img src="'+k+'" alt=""></a></p><p><strong>5b)</strong> <strong>搞清楚给小朋友写邮件时怎么落款。</strong></p><p>类似的情况。对疏远的人,我们有各种自动填充——Best、Regards、Talk soon、Take care、Thanks 等等——而真正亲近的人根本不需要落款。但对小朋友,我们又得来上另一整套花式操作。</p><p>我有时候会给小朋友的邮件结尾写「Thanks,」然后看着它想:「呃,太正式了。」然后我叹口气,把光标放到词尾,不情不愿地再打两个 S。</p><p>还值得一提的是,有些人认定 xoxo 是合适的落款,因为他们就是那么可爱,还有一些人则决定只用自己名字的首字母落款,因为显然我们现在在谈恋爱了。对我来说,这两种落款都让我觉得,写的人打字时是这个样子:</p><p><a href="https://3.bp.blogspot.com/-pj4CQPJYDWk/Up74aJNXlmI/AAAAAAAAGgk/AhGZhVp_lHg/s1600/xoxo.png" target="_blank" rel="noreferrer"><img src="'+d+'" alt=""></a></p><p><strong>6) 说机器人套话,提醒你自己其实并没那么独特。</strong></p><p>“机器人短语” (Robot Phrase) 指的是那些常用的邮件套话——你之所以用,只是因为其他人都在用,而你也不是什么有创造力的人。</p><p><a href="https://3.bp.blogspot.com/-MpnxM3UVt1g/Up74ZdMEk4I/AAAAAAAAGgc/O4NO1S7wLi4/s1600/robot+phrases.png" target="_blank" rel="noreferrer"><img src="'+u+'" alt=""></a></p><p>这些千篇一律的机器人短语让我想起我自己的语音信箱录音:「嗨,这里是 Tim。请留言。」紧接着响起的是一个<em>真正的</em>机器人的声音,说着「请在滴声后录下您的留言,巴拉巴拉」——她和我在表达个性方面做得一样好——不幸的是,唯一的另一个选择就是搞点出人意料的东西,把自己弄成一个没必要的怪咖。</p><p>邮件机器人短语在社交层面上没有语音信箱机器人录音那么强制,但我们大多数人都懒得费脑筋想替代说法。不过每次打出这些短语,我都会因为自己是社会齿轮的一部分而稍微有点自我厌恶。</p><p><strong>7) 精通感叹号的博弈棋局。</strong></p><p>面对面交流时,我们有一百万种微妙的方式来表达语气。哪怕在电话里,没有面部表情和肢体动作,光靠语气也足够搞定。</p><p>但在邮件里,我们只能靠一套粗糙的符号工具来表达细微差别,这就让标点成为了邮件世界里至关重要的一部分。几条准则:</p><p>有些人不用感叹号,和这类人交流时,坚持用句号是安全的。</p><p><a href="https://2.bp.blogspot.com/-JDVfXdjvsYs/Up8WChspO4I/AAAAAAAAGho/_ojZBn624uo/s1600/periods.png" target="_blank" rel="noreferrer"><img src="'+y+'" alt=""></a></p><p>另一些人则不停地用感叹号,和这种人交流时,你不用感叹号就是个大混蛋,所以你被迫加入这场狂欢。</p><p><a href="https://2.bp.blogspot.com/-FrkyONYxVC0/Up8WC7JU1NI/AAAAAAAAGhk/O0hCTjAbfgc/s1600/exclamations.png" target="_blank" rel="noreferrer"><img src="'+U+'" alt=""></a></p><p>这一点很重要,因为对一个狂热的感叹号使用者来说,句号和感叹号的区别看起来是这样的:</p><p><a href="https://4.bp.blogspot.com/-JGeGsNoOc7Y/Up74Tn2iPbI/AAAAAAAAGec/OQJHNFwj6S8/s1600/exclamation+period.png" target="_blank" rel="noreferrer"><img src="'+G+'" alt=""></a></p><p>还有一种罕见但灾难性的错误:感叹号 / 问号打错的手滑。</p><p><a href="https://1.bp.blogspot.com/-PGSsHTKKsNQ/Up74TzsNdUI/AAAAAAAAGeQ/dmqMQ3E3UtA/s1600/exclamation+question.png" target="_blank" rel="noreferrer"><img src="'+I+'" alt=""></a></p><p>我用不用感叹号都行,一般都是跟着对方走,但我发现有一个相当强的相关性:</p><p><a href="https://3.bp.blogspot.com/-RuJnc1WMo7A/Up74TYi6aDI/AAAAAAAAGeE/YWykUSRw5J0/s1600/exclamation+graph.png" target="_blank" rel="noreferrer"><img src="'+T+'" alt=""></a></p><p>省略号又完全是另一回事了。有些人用它来营造神秘感或威胁感,当然,它也可以非常骚。</p><p><a href="https://4.bp.blogspot.com/-_aarPJKTtaA/Up8RZhfCsqI/AAAAAAAAGhQ/7mTNbHGC41o/s1600/ellipses.png" target="_blank" rel="noreferrer"><img src="'+H+'" alt=""></a></p><p><strong>8) 双方都不想参与、却停不下来的史诗级通信。</strong></p><p><a href="https://4.bp.blogspot.com/-ot4raG6fQ3A/Up74TaUwn1I/AAAAAAAAGeA/VtzhfZcb60Y/s1600/epic+correspondence.png" target="_blank" rel="noreferrer"><img src="'+x+'" alt=""></a></p><p>这是电子邮件独有的一种非常奇怪的现象。它发生在两个关系没那么铁的朋友之间——他们莫名其妙地陷入了一种相互义务式的苦差事:每隔几个月就要给对方写一封长长的、描述自己近况生活的邮件。双方都害怕要回答上一封邮件里的所有问题、还要再写一大段生活流水账,而且各自读对方那封的时候也觉得挺无聊的。</p><p>这个循环要么一直持续到其中一人去世为止,要么有时候,某一方终于鼓起勇气就那么不回对方的邮件了,然后双方都长舒一口气。</p><p><strong>9) 试图把&quot;笑&quot;这个概念硬塞进电子邮件里。</strong></p><p><a href="https://2.bp.blogspot.com/-lKxBD8Qsexk/Up74VOjyViI/AAAAAAAAGew/yt0rXw4jTHo/s1600/haha.png" target="_blank" rel="noreferrer"><img src="'+q+'" alt=""></a></p><p>笑声是口头交流中令人愉快的一部分,所以我们决定得想办法在邮件里表达同样的东西——但这事儿很别扭。</p><p>先把那些说 lol 的荒谬之人排除在外,我们要面对的是这样一套体系:</p><p><strong>haha</strong> — 这事儿我觉得要么有点好笑,要么根本不好笑</p><p><strong>hahaha</strong> — 我觉得有一点点好笑</p><p><strong>hahahaha</strong> — 我觉得还挺好笑的</p><p><strong>HA</strong> 或 <strong>HAHA</strong> 或 <strong>HAHAHAHA</strong> — 我觉得非常好笑</p><p><strong>hahah</strong> 或 <strong>hahahah</strong> — 我是个很不合格的人类</p><p>至少在我的世界里,我发现当一件事真的好笑时,它一定会带出大写字母。</p><p>而且几乎在上述所有情况下,收件人脑子里都会想象发件人一边打字一边真的在笑,而事实上,他们很可能长得像上面图里那个哥们儿。</p><p><strong>10) 有些伤害性的事情正在你身上发生,而你根本没意识到。</strong></p><p><a href="https://4.bp.blogspot.com/-CiP-PH3841I/Up74Vcnw9wI/AAAAAAAAGfA/jatrL1cErfs/s1600/hurtful.png" target="_blank" rel="noreferrer"><img src="'+Y+'" alt=""></a></p><p>被假 haha 敷衍过,还只是开始。</p><p>你知道人们有时候在写邮件时会用密送 (BCC) 悄悄把某人拉进来吧?那你知道你<em>没</em>考虑过的是什么吗?就是当你收到某人的邮件时,里面正在进行一次你毫不知情的密送——<em>你</em>才是那个被暗中监视的傻瓜。挺让人不爽的对吧?</p><p>再比如说,你身处一堆群邮件链里,有些是一次性的,有些是周期性的——你大概就默认这些就是所有正在进行的群聊了。而事实上,你的各种朋友或家人之间还有一大堆群邮件链,你<em>不</em>在里面,你甚至从来没想过它们的存在。</p><p>更糟的是,想想你曾经把某人发给你的邮件转发给别人来嘲笑的那些时刻。有点损,但你确实干过对吧?那么某一时刻,你自己也是别人偷偷转发嘲笑的对象,这有多糟糕?</p><p>幸运的是,我们通常会避免去设想这些事正在发生。但它们就是在发生。</p><p><strong>11) 邮件灾难。</strong></p><p><a href="https://4.bp.blogspot.com/-A1dip5WZVpg/Up74Sm61qQI/AAAAAAAAGd8/2xYNuZGBjTY/s1600/disaster.png" target="_blank" rel="noreferrer"><img src="'+P+'" alt=""></a><br><a href="https://1.bp.blogspot.com/-BJAQVY6Qxso/Up74SQdvogI/AAAAAAAAGdk/kV9LL9oQ5tU/s1600/disaster+2.png" target="_blank" rel="noreferrer"><img src="'+S+'" alt=""></a></p><p>邮件灾难是一种特殊的灾难。它可能让你无地自容、伤感情,甚至毁掉一段友谊。</p><p>例子包括:</p><p>——给 X 发邮件说 Y 的坏话,结果一不小心发给了 Y。</p><p>——在群组邮件里想单独回复 X 说点私密的话,结果一不小心「回复全部」了。</p><p>——把一封邮件转发给某人,忘了下面还有一整串对话记录,里面有敏感内容,甚至可能就是关于你刚刚转发的那个人的。</p><h2 id="——给某人发附件-结果一不小心附上了错误的、恐怖的东西。" tabindex="-1">——给某人发附件,结果一不小心附上了错误的、恐怖的东西。 <a class="header-anchor" href="#——给某人发附件-结果一不小心附上了错误的、恐怖的东西。" aria-label="Permalink to &quot;——给某人发附件,结果一不小心附上了错误的、恐怖的东西。&quot;">​</a></h2><p>如果你喜欢 Wait But Why,请订阅我们的**<a href="https://newsletter.waitbutwhy.com/join" target="_blank" rel="noreferrer">邮件列表</a>**,新文章发布时我们会通知你。</p><p>想支持 Wait But Why,请访问我们的**<a href="https://patreon.com/waitbutwhy" target="_blank" rel="noreferrer">Patreon 页面</a>**。</p><p><strong>______</strong></p><p><strong>更多关于生活的尴尬时刻:</strong></p><p><strong><a href="https://waitbutwhy.com/2014/01/the-great-perils-of-social-interaction.html" target="_blank" rel="noreferrer">社交互动的巨大险境 (The Great Perils of Social Interaction)</a></strong></p><p><strong><a href="https://waitbutwhy.com/2014/12/10-types-odd-friendships-youre-probably-part.html" target="_blank" rel="noreferrer">你多半也身处其中的 10 种奇怪友谊 (10 Types of Odd Friendships You&#39;re Probably Part Of)</a></strong></p><p><strong><a href="https://waitbutwhy.com/2014/05/secretly-hate-bars.html" target="_blank" rel="noreferrer">你为什么暗自讨厌高档酒吧 (Why You Secretly Hate Cool Bars)</a></strong></p><p>还有,当有人拖了很久才回我邮件时,<strong><a href="https://waitbutwhy.com/2016/03/long-email-delay.html" target="_blank" rel="noreferrer">会发生这样的事</a></strong>。</p><p><a href="https://twitter.com/share" target="_blank" rel="noreferrer">Tweet</a></p><p><a href="//www.pinterest.com/pin/create/button/?url=https://waitbutwhy.com/2013/12/11-awkward-things-about-email.html&amp;description=11%20Awkward%20Things%20About%20Email" target="_blank" rel="noreferrer"><img src="'+Z+'" alt=""></a></p>',106)])])}const L=r(j,[["render",E]]);export{C as __pageData,L as default};
